arguments.argument:
if global.gamePaused=false
{
  myDist=point_distance(x,y,oPlayer1.x,oPlayer1.y)
  if myDist<10
  {
    if scrController(3)
    {
      if isCollisionTop(1)
        yVel=0
      else
        yVel=-4
    }
    else if scrController(4)
    {
      if isCollisionBottom(1)
        yVel=0
      else
        yVel=4
    }
    else {yVel=0}
    
    if yVel!=0
    {
      if soundDelay=0
      {
        //sound_play(snd_ElevatorUse)
        soundDelay=4
      }
      else {soundDelay-=1}
    }
  }
  else {yVel=0}
}
